-- ────────────────────────────────────────────────────────────
-- MODULE 5: EXAMINATION BOOKING
-- ────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS exam_series (
    id          SERIAL PRIMARY KEY,
    name        VARCHAR(100) NOT NULL,          -- e.g. "July/August 2026 CDACC"
    start_date  DATE NOT NULL,
    end_date    DATE NOT NULL,
    deadline    DATE NOT NULL,                  -- registration deadline
    is_active   BOOLEAN NOT NULL DEFAULT TRUE,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS assessment_centers (
    id          SERIAL PRIMARY KEY,
    name        VARCHAR(200) NOT NULL,
    location    VARCHAR(200),
    is_active   BOOLEAN NOT NULL DEFAULT TRUE
);

-- Insert default assessment center
INSERT INTO assessment_centers (name, location) VALUES
    ('Thika Technical Training Institute', 'Thika, Kiambu County')
ON CONFLICT DO NOTHING;

CREATE TABLE IF NOT EXISTS exam_bookings (
    id                  SERIAL PRIMARY KEY,
    student_id          INT NOT NULL REFERENCES students(id) ON DELETE CASCADE,
    series_id           INT NOT NULL REFERENCES exam_series(id) ON DELETE CASCADE,
    center_id           INT REFERENCES assessment_centers(id) ON DELETE SET NULL,
    -- Candidate details (snapshot at booking time)
    full_name           VARCHAR(200) NOT NULL,
    admission_number    VARCHAR(50)  NOT NULL,
    course_code         VARCHAR(50),
    course_name         VARCHAR(200),
    module_level        VARCHAR(100),
    gender              VARCHAR(10),
    date_of_birth       DATE,
    mobile_number       VARCHAR(20),
    email               VARCHAR(100),
    national_id         VARCHAR(50),
    pwd_status          VARCHAR(50),
    -- Required uploads (Supabase Storage paths)
    national_id_doc     TEXT,   -- path to uploaded file
    birth_cert_doc      TEXT,
    kcse_cert_doc       TEXT,
    result_slip_doc     TEXT,
    fee_statement_doc   TEXT,
    -- Approval workflow
    status              VARCHAR(20) NOT NULL DEFAULT 'pending'
                        CHECK (status IN ('pending','hod_approved','registrar_approved','rejected')),
    hod_approved_by     UUID REFERENCES auth.users(id) ON DELETE SET NULL,
    hod_approved_at     TIMESTAMPTZ,
    hod_comment         TEXT,
    registrar_approved_by UUID REFERENCES auth.users(id) ON DELETE SET NULL,
    registrar_approved_at TIMESTAMPTZ,
    registrar_comment   TEXT,
    -- QR code token for verification
    qr_token            VARCHAR(64) UNIQUE DEFAULT encode(gen_random_bytes(32), 'hex'),
    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE (student_id, series_id)
);

CREATE TABLE IF NOT EXISTS exam_booking_units (
    id              SERIAL PRIMARY KEY,
    booking_id      INT NOT NULL REFERENCES exam_bookings(id) ON DELETE CASCADE,
    unit_id         INT NOT NULL REFERENCES units(id) ON DELETE CASCADE,
    unit_type       VARCHAR(20) DEFAULT 'Core' CHECK (unit_type IN ('Core','Common','Basic')),
    unit_cost       NUMERIC(10,2) DEFAULT 0,
    UNIQUE (booking_id, unit_id)
);

CREATE TRIGGER trg_exam_bookings_updated_at
    BEFORE UPDATE ON exam_bookings
    FOR EACH ROW EXECUTE FUNCTION set_updated_at();

-- ────────────────────────────────────────────────────────────
-- MODULE 8: INTERNAL VERIFICATION
-- ────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS iv_assignments (
    id              SERIAL PRIMARY KEY,
    verifier_id     UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    trainer_id      INT  NOT NULL REFERENCES trainers(id)   ON DELETE CASCADE,
    unit_id         INT  NOT NULL REFERENCES units(id)      ON DELETE CASCADE,
    class_id        INT  NOT NULL REFERENCES classes(id)    ON DELETE CASCADE,
    year            INT  NOT NULL DEFAULT EXTRACT(YEAR FROM NOW())::INT,
    term            INT  NOT NULL DEFAULT 1,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE (verifier_id, trainer_id, unit_id, class_id, year, term)
);

CREATE TABLE IF NOT EXISTS iv_reviews (
    id              SERIAL PRIMARY KEY,
    assignment_id   INT  NOT NULL REFERENCES iv_assignments(id) ON DELETE CASCADE,
    student_id      INT  NOT NULL REFERENCES students(id)       ON DELETE CASCADE,
    -- Evidence verification
    evidence_status VARCHAR(20) NOT NULL DEFAULT 'pending'
                    CHECK (evidence_status IN ('pending','approved','rejected','needs_revision')),
    assessment_status VARCHAR(20) NOT NULL DEFAULT 'pending'
                    CHECK (assessment_status IN ('pending','approved','rejected','needs_revision')),
    comments        TEXT,
    recommendations TEXT,
    -- Digital signature (base64 or path)
    verifier_signature TEXT,
    signed_at       TIMESTAMPTZ,
    -- Compliance
    compliance_score INT CHECK (compliance_score BETWEEN 0 AND 100),
    version         INT NOT NULL DEFAULT 1,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE (assignment_id, student_id)
);

CREATE TABLE IF NOT EXISTS iv_review_history (
    id          BIGSERIAL PRIMARY KEY,
    review_id   INT NOT NULL REFERENCES iv_reviews(id) ON DELETE CASCADE,
    changed_by  UUID REFERENCES auth.users(id) ON DELETE SET NULL,
    old_status  VARCHAR(20),
    new_status  VARCHAR(20),
    comment     TEXT,
    version     INT,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TRIGGER trg_iv_reviews_updated_at
    BEFORE UPDATE ON iv_reviews
    FOR EACH ROW EXECUTE FUNCTION set_updated_at();

-- ────────────────────────────────────────────────────────────
-- MODULE 9: EXTERNAL VERIFICATION
-- ────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS ev_verifiers (
    id              SERIAL PRIMARY KEY,
    user_id         UUID UNIQUE REFERENCES auth.users(id) ON DELETE SET NULL,
    full_name       VARCHAR(200) NOT NULL,
    email           VARCHAR(100),
    organization    VARCHAR(200),
    is_active       BOOLEAN NOT NULL DEFAULT TRUE,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS ev_assignments (
    id              SERIAL PRIMARY KEY,
    verifier_id     INT  NOT NULL REFERENCES ev_verifiers(id)  ON DELETE CASCADE,
    department_id   INT  NOT NULL REFERENCES departments(id)   ON DELETE CASCADE,
    unit_id         INT  REFERENCES units(id)                  ON DELETE SET NULL,
    year            INT  NOT NULL DEFAULT EXTRACT(YEAR FROM NOW())::INT,
    term            INT  NOT NULL DEFAULT 1,
    visit_date      DATE,
    status          VARCHAR(20) NOT NULL DEFAULT 'scheduled'
                    CHECK (status IN ('scheduled','in_progress','completed','cancelled')),
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS ev_reports (
    id                  SERIAL PRIMARY KEY,
    assignment_id       INT  NOT NULL REFERENCES ev_assignments(id) ON DELETE CASCADE,
    -- Moderation findings
    compliance_score    INT  CHECK (compliance_score BETWEEN 0 AND 100),
    overall_verdict     VARCHAR(20) NOT NULL DEFAULT 'pending'
                        CHECK (overall_verdict IN ('pending','satisfactory','unsatisfactory','conditional')),
    findings            TEXT,
    recommendations     TEXT,
    -- Digital signature
    verifier_signature  TEXT,
    signed_at           TIMESTAMPTZ,
    -- Approval
    approved_by         UUID REFERENCES auth.users(id) ON DELETE SET NULL,
    approved_at         TIMESTAMPTZ,
    -- Audit
    version             INT NOT NULL DEFAULT 1,
    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS ev_report_history (
    id          BIGSERIAL PRIMARY KEY,
    report_id   INT NOT NULL REFERENCES ev_reports(id) ON DELETE CASCADE,
    changed_by  UUID REFERENCES auth.users(id) ON DELETE SET NULL,
    action      VARCHAR(50),
    detail      JSONB,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TRIGGER trg_ev_reports_updated_at
    BEFORE UPDATE ON ev_reports
    FOR EACH ROW EXECUTE FUNCTION set_updated_at();

-- ────────────────────────────────────────────────────────────
-- MODULE 10: DUAL TRAINING MANAGEMENT
-- ────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS employers (
    id              SERIAL PRIMARY KEY,
    company_name    VARCHAR(200) NOT NULL,
    contact_person  VARCHAR(200),
    email           VARCHAR(100),
    phone           VARCHAR(30),
    address         TEXT,
    industry_sector VARCHAR(100),
    is_active       BOOLEAN NOT NULL DEFAULT TRUE,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS dual_training_allocations (
    id              SERIAL PRIMARY KEY,
    student_id      INT  NOT NULL REFERENCES students(id)  ON DELETE CASCADE,
    employer_id     INT  NOT NULL REFERENCES employers(id) ON DELETE CASCADE,
    trainer_id      INT  REFERENCES trainers(id)           ON DELETE SET NULL,
    start_date      DATE NOT NULL,
    end_date        DATE NOT NULL,
    status          VARCHAR(20) NOT NULL DEFAULT 'active'
                    CHECK (status IN ('active','completed','withdrawn','suspended')),
    -- Competency tracking
    competencies    JSONB,   -- array of {name, status, date_achieved}
    -- Practical hours
    required_hours  INT NOT NULL DEFAULT 480,
    logged_hours    INT NOT NULL DEFAULT 0,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE (student_id, employer_id, start_date)
);

CREATE TABLE IF NOT EXISTS dual_training_attendance (
    id              SERIAL PRIMARY KEY,
    allocation_id   INT  NOT NULL REFERENCES dual_training_allocations(id) ON DELETE CASCADE,
    date            DATE NOT NULL,
    check_in        TIME,
    check_out       TIME,
    hours_logged    NUMERIC(4,2) DEFAULT 0,
    status          VARCHAR(20) NOT NULL DEFAULT 'present'
                    CHECK (status IN ('present','absent','late','excused')),
    note            TEXT,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS dual_training_feedback (
    id              SERIAL PRIMARY KEY,
    allocation_id   INT  NOT NULL REFERENCES dual_training_allocations(id) ON DELETE CASCADE,
    submitted_by    UUID REFERENCES auth.users(id) ON DELETE SET NULL,
    feedback_type   VARCHAR(20) NOT NULL DEFAULT 'weekly'
                    CHECK (feedback_type IN ('weekly','monthly','final')),
    week_number     INT,
    -- Competency scores (1-5)
    punctuality     INT CHECK (punctuality BETWEEN 1 AND 5),
    technical_skills INT CHECK (technical_skills BETWEEN 1 AND 5),
    discipline      INT CHECK (discipline BETWEEN 1 AND 5),
    communication   INT CHECK (communication BETWEEN 1 AND 5),
    safety_awareness INT CHECK (safety_awareness BETWEEN 1 AND 5),
    teamwork        INT CHECK (teamwork BETWEEN 1 AND 5),
    initiative      INT CHECK (initiative BETWEEN 1 AND 5),
    overall_score   NUMERIC(4,2),
    comments        TEXT,
    employer_signature TEXT,
    signed_at       TIMESTAMPTZ,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TRIGGER trg_dual_training_updated_at
    BEFORE UPDATE ON dual_training_allocations
    FOR EACH ROW EXECUTE FUNCTION set_updated_at();

-- ────────────────────────────────────────────────────────────
-- MODULE 11: INDUSTRIAL ATTACHMENT & DIGITAL LOGBOOK
-- ────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS attachment_placements (
    id              SERIAL PRIMARY KEY,
    student_id      INT  NOT NULL REFERENCES students(id)  ON DELETE CASCADE,
    employer_id     INT  REFERENCES employers(id)          ON DELETE SET NULL,
    trainer_id      INT  REFERENCES trainers(id)           ON DELETE SET NULL,
    supervisor_id   UUID REFERENCES auth.users(id)         ON DELETE SET NULL,
    organization    VARCHAR(200) NOT NULL,
    location        VARCHAR(200),
    start_date      DATE NOT NULL,
    end_date        DATE NOT NULL,
    status          VARCHAR(20) NOT NULL DEFAULT 'active'
                    CHECK (status IN ('active','completed','withdrawn')),
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Allowed submission slots: 7am,9am,11am,1pm,3pm,5pm,7pm
CREATE TABLE IF NOT EXISTS logbook_entries (
    id              BIGSERIAL PRIMARY KEY,
    placement_id    INT  NOT NULL REFERENCES attachment_placements(id) ON DELETE CASCADE,
    student_id      INT  NOT NULL REFERENCES students(id)              ON DELETE CASCADE,
    -- Submission slot (server-assigned, backdate-prevented)
    submission_slot VARCHAR(10) NOT NULL,   -- '07:00','09:00','11:00','13:00','15:00','17:00','19:00'
    entry_date      DATE NOT NULL,
    submitted_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    -- Activity details
    activity_title  VARCHAR(200) NOT NULL,
    description     TEXT NOT NULL,
    skills_gained   TEXT,
    tools_materials TEXT,
    challenges      TEXT,
    time_spent      NUMERIC(4,2),           -- hours
    -- Evidence (Supabase Storage paths, comma-separated or JSON array)
    evidence_files  TEXT,
    -- Location
    gps_latitude    NUMERIC(10,7),
    gps_longitude   NUMERIC(10,7),
    location_name   VARCHAR(200),
    -- Approval
    status          VARCHAR(20) NOT NULL DEFAULT 'pending'
                    CHECK (status IN ('pending','approved','rejected')),
    supervisor_comment TEXT,
    approved_by     UUID REFERENCES auth.users(id) ON DELETE SET NULL,
    approved_at     TIMESTAMPTZ,
    -- Prevent backdating: entry_date must be <= submitted_at date
    CONSTRAINT no_backdate CHECK (entry_date <= submitted_at::DATE),
    UNIQUE (placement_id, student_id, entry_date, submission_slot)
);

CREATE TABLE IF NOT EXISTS attachment_supervisors (
    id          SERIAL PRIMARY KEY,
    user_id     UUID UNIQUE REFERENCES auth.users(id) ON DELETE SET NULL,
    full_name   VARCHAR(200) NOT NULL,
    email       VARCHAR(100),
    employer_id INT REFERENCES employers(id) ON DELETE SET NULL,
    phone       VARCHAR(30),
    is_active   BOOLEAN NOT NULL DEFAULT TRUE,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS supervisor_evaluations (
    id              SERIAL PRIMARY KEY,
    placement_id    INT  NOT NULL REFERENCES attachment_placements(id) ON DELETE CASCADE,
    supervisor_id   UUID NOT NULL REFERENCES auth.users(id)            ON DELETE CASCADE,
    week_number     INT  NOT NULL,
    -- Scores (1-5)
    punctuality     INT CHECK (punctuality BETWEEN 1 AND 5),
    technical_skills INT CHECK (technical_skills BETWEEN 1 AND 5),
    discipline      INT CHECK (discipline BETWEEN 1 AND 5),
    communication   INT CHECK (communication BETWEEN 1 AND 5),
    safety_awareness INT CHECK (safety_awareness BETWEEN 1 AND 5),
    teamwork        INT CHECK (teamwork BETWEEN 1 AND 5),
    initiative      INT CHECK (initiative BETWEEN 1 AND 5),
    overall_score   NUMERIC(4,2),
    comments        TEXT,
    supervisor_signature TEXT,
    signed_at       TIMESTAMPTZ,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    UNIQUE (placement_id, supervisor_id, week_number)
);

