-- Super admin: full access to all new tables
DO $$
DECLARE
    tbl TEXT;
    tbls TEXT[] := ARRAY[
        'exam_series','assessment_centers','exam_bookings','exam_booking_units',
        'iv_assignments','iv_reviews','iv_review_history',
        'ev_verifiers','ev_assignments','ev_reports','ev_report_history',
        'employers','dual_training_allocations','dual_training_attendance','dual_training_feedback',
        'attachment_placements','logbook_entries','attachment_supervisors','supervisor_evaluations'
    ];
BEGIN
    FOREACH tbl IN ARRAY tbls LOOP
        EXECUTE format(
            'CREATE POLICY %I ON %I FOR ALL TO authenticated
             USING (current_user_role() = ''super_admin'' AND current_user_active())
             WITH CHECK (current_user_role() = ''super_admin'' AND current_user_active())',
            'sa_full_' || tbl, tbl
        );
    END LOOP;
END $$;

-- Students: read/write their own exam bookings and logbook entries
CREATE POLICY student_own_bookings ON exam_bookings
    FOR ALL TO authenticated
    USING (student_id IN (SELECT id FROM students WHERE user_id = auth.uid()) AND current_user_active())
    WITH CHECK (student_id IN (SELECT id FROM students WHERE user_id = auth.uid()) AND current_user_active());

CREATE POLICY student_own_logbook ON logbook_entries
    FOR ALL TO authenticated
    USING (student_id IN (SELECT id FROM students WHERE user_id = auth.uid()) AND current_user_active())
    WITH CHECK (student_id IN (SELECT id FROM students WHERE user_id = auth.uid()) AND current_user_active());

